class Solution:
    def countNumbers(self, l: str, r: str, b: int) -> int:
        def is_non_decreasing(num_str):
            return all(int(num_str[i]) <= int(num_str[i+1]) for i in range(len(num_str)-1))

        l_int = int(l, b)
        r_int = int(r, b)
        count = 0
        for i in range(l_int, r_int + 1):
            num_str = bin(i)[2:]
            if is_non_decreasing(num_str):
                count += 1
        return count % (10**9 + 7)
